```

### Step 4: 注入 window.KPI_DATA（L678 之后）

```js
'window.KPI_DATA = ' + JSON.stringify(kpiJson) + ';\n' +
```

### Step 5: 新增 openKpiModal 函数

在 `openModal` 函数（L689）之前插入：
```js
function openKpiModal(key) {
  var data = window.KPI_DATA[key] || [];
  document.getElementById("modal-title").innerHTML = esc(key) + " — " + data.length + "人";
  var rows = "";
  for (var i = 0; i < data.length; i++) {
    var c = data[i];
    rows += "<tr><td>" + gradeTag(c.g) + "<strong>" + esc(c.n) + "</strong></td><td style=\"text-align:center;white-space:nowrap;font-size:11px;\">" + esc(c.c) + " · " + (c.d === 999 ? "?" : c.d + "d") + "</td><td style=\"font-size:12px;\">" + (c.as ? '⚠️ 售后待确认 — ' : '') + esc(c.st) + "</td><td style=\"color:var(--text-primary);font-weight:600;font-size:12px;\">" + prioIcon(c.pr) + " " + esc(c.ac) + "</td></tr>";
  }
  document.getElementById("modal-body").innerHTML =
    '<div style="max-height:55vh;overflow-y:auto;"><table><tr><th style="width:140px;">客户</th><th style="text-align:center;width:100px;">国家 · 静默</th><th>当前状态</th><th>行动方向</th></tr>' + rows + '</table></div>' +
